const campaign = $input.first().json.body;
return [{
  json: {
    campaignId: campaign.campaignId,
    serviceDescription: campaign.serviceDescription || 'AI-powered lead generation',
    tone: campaign.tone || 'friendly',
    specialOffer: campaign.specialOffer || '',
    channels: campaign.channels || ['email', 'whatsapp']
  }
}];

const campaign = $('Extract Campaign Config').first().json;
const leads = $input.all();
return leads.map(lead => ({
  json: { ...lead.json, campaignId: campaign.campaignId, serviceDescription: campaign.serviceDescription, tone: campaign.tone, specialOffer: campaign.specialOffer, channels: campaign.channels }
}));

const lead = $('Merge Lead + Campaign').first().json;
const response = $input.first().json;
const aiText = response.candidates[0].content.parts[0].text;
const aiOutput = JSON.parse(aiText);

const messages = [];
const channelList = lead.channels || ['email'];

if (channelList.includes('whatsapp') && aiOutput.message_whatsapp) {
  messages.push({ lead_id: lead.id, campaign_id: lead.campaignId, channel: 'whatsapp', content: aiOutput.message_whatsapp, type: 'initial', status: 'pending' });
}
if (channelList.includes('email') && aiOutput.message_email_body) {
  messages.push({ lead_id: lead.id, campaign_id: lead.campaignId, channel: 'email', content: JSON.stringify({ subject: aiOutput.message_email_subject, body: aiOutput.message_email_body }), type: 'initial', status: 'pending' });
}
if (channelList.includes('linkedin') && aiOutput.message_linkedin) {
  messages.push({ lead_id: lead.id, campaign_id: lead.campaignId, channel: 'linkedin', content: aiOutput.message_linkedin, type: 'initial', status: 'pending' });
}

const followups = [
  { type: 'followup1', content: aiOutput.followup_day3, days: 3 },
  { type: 'followup2', content: aiOutput.followup_day6, days: 6 },
  { type: 'followup3', content: aiOutput.followup_day10, days: 10 }
];
for (const fu of followups) {
  if (fu.content) {
    const d = new Date(); d.setDate(d.getDate() + fu.days);
    messages.push({ lead_id: lead.id, campaign_id: lead.campaignId, channel: channelList[0], content: fu.content, type: fu.type, status: 'scheduled', scheduled_at: d.toISOString() });
  }
}

return messages.map(m => ({ json: m }));
